import React, { useState } from "react";
import BusMap from "./BusMap";
import BusCharts from "./BusCharts";
import Alerts from "./Alerts";

function App() {
  const [showChart, setShowChart] = useState(false);
  const [chartData, setChartData] = useState([
    { time: "10:00", Normal: 5, Ghost: 2 },
    { time: "10:02", Normal: 6, Ghost: 1 },
  ]); // sample chart, update dynamically if needed

  return (
    <div>
      <h1>Ghost Bus Detector</h1>
      <Alerts />
      <BusMap />
      <button onClick={() => setShowChart(!showChart)} style={{ marginTop: "10px" }}>
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>
      {showChart && <BusCharts data={chartData} />}
    </div>
  );
}

export default App;
